class Solution:
    def reinitializePermutation(self, n):
        """
        :type n: int
        :rtype: int
        """
        perm = list(range(n))
        original = list(range(n))
        ops = 0

        while True:
            # Apply operation
            arr = [0] * n
            for i in range(n):
                if i % 2 == 0:
                    arr[i] = perm[i // 2]
                else:
                    arr[i] = perm[n // 2 + (i - 1) // 2]
            perm = arr
            ops += 1

            if perm == original:
                return ops
